CREATE TABLE vendor_to_technology
(
	id serial,
	vendor_id integer NOT NULL,
	technology_id integer DEFAULT NULL,
	CONSTRAINT pk_vendor_to_technology PRIMARY KEY (id)
	, CONSTRAINT fk_vendor_to_technology_to_vendor FOREIGN KEY (vendor_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_vendor_to_technology_to_data_type FOREIGN KEY (technology_id) REFERENCES technologies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_vendor_to_technology_vendor ON vendor_to_technology (vendor_id);
CREATE INDEX i_vendor_to_technology_technology ON vendor_to_technology (technology_id);
